import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';

class MyInfo extends React.Component {
    constructor(props) {
        super(props);
        this.state = { name: '', birthday: '', age: '', nameValidated: false, birthdayValidated: false, ageValidated: false };
    }

    handleChange = (event) => {
        const { name, value } = event.target;
        this.setState({
            [name]: value
        });
    }

    handleValidateName = () => {
        var nameValidationBlock = document.getElementById('myName');
        const { name } = this.state;
        if (name.trim() !== '') {
            this.setState({ nameValidated: true });
            nameValidationBlock.style.display = "none";
        } else {
            alert("Please enter a valid name.");
        }
    }

    handleValidateBirthday = () => {
        var birthdayValidationBlock = document.getElementById('myBirthday');
        const { birthday } = this.state;
        if (birthday.trim() !== '') {
            this.setState({ birthdayValidated: true });
            birthdayValidationBlock.style.display = "none";
        } else {
            alert("Please enter a valid birthday.");
        }
    }

    handleValidateAge = () => {
        var ageValidationBlock = document.getElementById('myAge');
        const { age } = this.state;
        if (age.trim() !== '') {
            this.setState({ ageValidated: true });
            ageValidationBlock.style.display = "none";
        } else {
            alert("Please enter a valid age.");
        }
    }

    render() {
        const { name, birthday, age, nameValidated, birthdayValidated, ageValidated } = this.state;

        return (
            <div>

                <div id='myName'>
                    <h2>Let's start with you.</h2>
                    <h2>What is your name?</h2>
                    <label>Name: </label>
                    <input type="text" name="name" value={name} onChange={this.handleChange} />
                    <br />
                    <br />
                </div>
                
                {!nameValidated && (
                    <button onClick={this.handleValidateName}>Validate Name</button>
                )}
                {nameValidated && (
                    <>
                        
                        <div id='myBirthday'>
                            <h2>When is your birthday?</h2>
                            <label>Birthday: </label>
                            <input type="text" name="birthday" value={birthday} onChange={this.handleChange} />
                            <br />
                            <br />
                        </div>

                        {!birthdayValidated && (
                            <button onClick={this.handleValidateBirthday}>Validate Birthday</button>
                        )}
                        {birthdayValidated && (
                            <>

                                <div id='myAge'>
                                    <h2>How old are you?</h2>
                                    <label>Age: </label>
                                    <input type="text" name="age" value={age} onChange={this.handleChange} />
                                    <br />
                                    <br />
                                </div>

                                {!ageValidated && (
                                    <button onClick={this.handleValidateAge}>Validate Age</button>
                                )}
                                {ageValidated && (
                                    <>
                                        <Node name={name} birthday={birthday} age={age} />
                                    </>
                                )}

                            </>

                        )}

                    </>

                )}

            </div>
        );
    }
}

class Node extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            isFocused: false,
            nodes: [] // Array to store nodes
        };
    }

    handleFocus = () => {
        this.setState({ isFocused: true });
    }

    handleBlur = () => {
        
        this.setState({ isFocused: false });
    }

    handleLeftButtonClick = () => {
        // Create a new node 128px above the current one
        const newNode = {
            name: 'New Parent',
            birthday: '01/01/2000',
            age: 24 // Set age as per requirement
        };
        this.setState(prevState => ({
            nodes: [newNode, ...prevState.nodes]
        }));
    }

    handleRightButtonClick = () => {
        console.log("Right button clicked");
    }

    render() {
        const { name, birthday, age } = this.props;
        const { isFocused, nodes } = this.state;

        return (
            <div className="node" onFocus={this.handleFocus} onBlur={this.handleBlur} tabIndex="0">
                {isFocused && (
                    <>
                        <button className="addParent" onClick={this.handleLeftButtonClick} style={{ position: 'absolute', top: '-32px', left: '50%', transform: 'translateX(-50%)' }}>+</button>
                        <button className="addChild" onClick={this.handleRightButtonClick} style={{ position: 'absolute', bottom: '-32px', left: '50%', transform: 'translateX(-50%)' }}>+</button>
                        <button className="addSpouse" onClick={this.handleLeftButtonClick} style={{ position: 'absolute', left: '-32px', top: '50%', transform: 'translateY(-50%)' }}>+</button>
                        <button className="addSibling" onClick={this.handleRightButtonClick} style={{ position: 'absolute', right: '-32px', top: '50%', transform: 'translateY(-50%)' }}>+</button>
                    </>
                )}
                {/* Render existing nodes */}
                {nodes.map((node, index) => (
                    <div key={index} style={{ marginBottom: '128px' }}>
                        <h2>{node.name}</h2>
                        <h2>{node.birthday} ({node.age})</h2>
                    </div>
                ))}
                <h2>{name}</h2>
                <h2>{birthday} ({age})</h2>
            </div>

        );
    }
}



ReactDOM.render(
    <React.StrictMode>
        <MyInfo />
    </React.StrictMode>,
    document.getElementById('root')
);
